#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=400005;
double a[N],tr1[N],tr2[N],laz1[N],laz2[N];
void pushup(int id)
{
	tr1[id]=tr1[id*2]+tr1[id*2+1];
	tr2[id]=tr2[id*2]+tr2[id*2+1];
}
void pushdown(int id,int l,int r)
{
	int mid=(l+r)/2;
	laz2[id*2]+=laz2[id];
	tr2[id*2]+=(tr1[id*2]*laz2[id]*2+(double)(mid-l+1)*(laz2[id]*laz2[id]));
	laz2[id*2+1]+=laz2[id];
	tr2[id*2+1]+=(tr1[id*2+1]*laz2[id]*2+(double)(r-mid)*(laz2[id]*laz2[id]));
	laz2[id]=0;
	laz1[id*2]+=laz1[id];
	tr1[id*2]+=(((double)mid-l+1)*laz1[id]);
	laz1[id*2+1]+=laz1[id];
	tr1[id*2+1]+=(((double)r-mid)*laz1[id]);
	laz1[id]=0;
}
void build(int id,int l,int r)
{
	if(l==r)
	{
		tr1[id]=a[l];
		tr2[id]=a[l]*a[l];
		return ;
	}
	int mid=(l+r)/2;
	build(id*2,l,mid);
	build(id*2+1,mid+1,r);
	pushup(id);
}
double query1(int id,int l,int r,int x,int y)
{
	if(l>y||r<x) return 0;
	if(x<=l&&r<=y) return tr1[id];
	int mid=(l+r)/2;
	if(laz1[id]) pushdown(id,l,r);
	double tmp=query1(id*2,l,mid,x,y)+query1(id*2+1,mid+1,r,x,y);
	pushup(id);
	return tmp;
}
double query2(int id,int l,int r,int x,int y)
{
	if(l>y||r<x) return 0;
	if(x<=l&&r<=y) return tr2[id];
	int mid=(l+r)/2;
	if(laz2[id]) pushdown(id,l,r);
	double tmp=query2(id*2,l,mid,x,y)+query2(id*2+1,mid+1,r,x,y);
	pushup(id);
	return tmp;
}
void update(int id,int l,int r,int x,int y,double num)
{
	if(l>y||r<x) return ;
	if(x<=l&&r<=y)
	{
		laz2[id]+=num;
		laz1[id]+=num;
		tr2[id]+=(tr1[id]*num*2+((double)r-l+1)*num*num);
		tr1[id]+=((double)r-l+1)*num;
		return ;
	}
	if(laz1[id]||laz2[id]) pushdown(id,l,r);
	int mid=(l+r)/2;
	update(id*2,l,mid,x,y,num);
	update(id*2+1,mid+1,r,x,y,num);
	pushup(id);
}
int n,m;
int main()
{
//	freopen("P1471_4.in","r",stdin);
//	freopen("P1471_4(my).out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	build(1,1,n);
	while(m--)
	{
		int op,x,y;
		double z;
		cin>>op;
		if(op==1)
		{
			cin>>x>>y>>z;
			update(1,1,n,x,y,z);
		}
		if(op==2)
		{
			cin>>x>>y;
			cout<<fixed<<setprecision(4)<<query1(1,1,n,x,y)/((double)(y-x+1))<<"\n";
		}
		if(op==3)
		{
			cin>>x>>y;
			double tmp=query1(1,1,n,x,y)/((double)(y-x+1));
			cout<<fixed<<setprecision(4)<<(query2(1,1,n,x,y)/((double)(y-x+1))-(tmp*tmp))<<"\n";
		}
	}
	return 0;
}
